+
+// getGitRootForMolStatus returns the git root for hook file lookup.
+func getGitRootForMolStatus() (string, error) {
+	cmd := exec.Command("git", "rev-parse", "--show-toplevel")
+	out, err := cmd.Output()
+	if err != nil {
+		return "", err
+	}
+	return strings.TrimSpace(string(out)), nil
+}
